steps.script:
var m = tree.current_scene
var sc = m.shooting_controller
var u = GameState.get_unit(str(sc.active_shooter_id))
var pos = null
for model in u.get("models", []):
	if model.get("alive", true):
		pos = model.get("position")
		break
if pos == null:
	return false
var screen = m.world_to_screen_position(Vector2(float(pos.x), float(pos.y)))
var vp = m.get_viewport().get_visible_rect().size
return screen.x >= 0.0 and screen.y >= 0.0 and screen.x <= vp.x and screen.y <= vp.y

var sc = tree.current_scene.shooting_controller
var sel = sc.unit_selector.get_selected_items()
if sel.size() == 0:
	return "no_row_selected"
return str(sc.unit_selector.get_item_metadata(sel[0])) == str(sc.active_shooter_id)
